// Function to delete a message from SQS after successful processing
async function deleteMessage(receiptHandle, messageId) {
    const deleteParams = {
        QueueUrl: SQS_QUEUE_URL,
        ReceiptHandle: receiptHandle,
    };
    try {
        await sqsClient.send(new DeleteMessageCommand(deleteParams));
        console.log(`Message ID ${messageId} with ReceiptHandle ${receiptHandle} deleted from queue.`);
        return true;
    } catch (error) {
        console.error(`Error deleting message ID ${messageId} with ReceiptHandle ${receiptHandle}:`, error);
        return false;
    }
}

// Main function to consume messages from SQS
async function consumeMessages() {
    const receiveParams = {
        QueueUrl: SQS_QUEUE_URL,
        MaxNumberOfMessages: 10, // Retrieve up to 10 messages at a time
        WaitTimeSeconds: 20,     // Use long polling (wait up to 20 seconds for messages)
        // Since we are skipping deduplication checks and aiming for speed,
        // we assume a Standard SQS queue, which does not require MessageDeduplicationId or MessageGroupId.
        // If message attributes are needed, uncomment: MessageAttributeNames: ['All'],
        // If system attributes are needed, uncomment: AttributeNames: ['All']
    };

    try {
        const { Messages } = await sqsClient.send(new ReceiveMessageCommand(receiveParams));

        if (Messages && Messages.length > 0) {
            console.log(`Received ${Messages.length} messages.`);
            // Process messages sequentially to ensure order for financial transactions if needed,
            // or in parallel if transactions are independent and idempotency is robust.
            for (const message of Messages) {
                const processingSuccessful = await processMessage(message);
                if (processingSuccessful) {
                    await deleteMessage(message.ReceiptHandle, message.MessageId);
                } else {
                    // If processing failed, the message will become visible again after
                    // the Queue's VisibilityTimeout expires. This allows for retries.
                    // For critical financial systems, consider integrating with a Dead-Letter Queue (DLQ)
                    // after a certain number of retries for manual investigation.
                    console.log(`Message ID ${message.MessageId} failed processing. It will be reprocessed after visibility timeout expires.`);
                }
            }
        } else {
            console.log('No messages received. Polling again...');
        }
    } catch (error) {
        console.error('Error receiving messages from SQS:', error);
    }
}

// Start the continuous consumer loop
const POLLING_INTERVAL_MS = 1000; // Time to wait between consecutive polls if no messages were found
let isProcessing = false;

async function startConsumerLoop() {
    if (isProcessing) {
        return; // Prevent multiple concurrent consumer calls if previous one is still running
    }
    isProcessing = true;
    try {
        await consumeMessages();
    } catch (error) {
        console.error('Unhandled error in consumer loop:', error);
    } finally {
        isProcessing = false;
        // Schedule the next poll. Use setTimeout to avoid blocking the event loop.
        setTimeout(startConsumerLoop, POLLING_INTERVAL_MS);
    }
}

console.log(`SQS Consumer for financial transactions started for queue: ${SQS_QUEUE_URL}`);
startConsumerLoop();

